#[test]
fn coredll_raw_ext_text_out_w_draws_glyphs_into_memory_dib() -> Result<()> {
    // ExtTextOutW with count=1 for 'A' should write text-color pixels into the bitmap.
    // Default font: height=16, ave_width=8. Glyph 'A' (FONT_8X8[33]):
    //   row 0 = 0x18 = 00011000 → cols 3 and 4 set.
    //   Screen rows 0..2 (glyph_row 0 scaled by 16/8=2), col 3.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let bad_hdc = 0x1234_5678;
    // 32×16 top-down RGB565 DIB gives enough room for the full 'A' glyph.
    let (mem_dc, bits_ptr, stride) =
        create_selected_rgb565_dib(&table, &mut kernel, &mut memory, thread_id, 32, 16);

    // Set text color to white (RGB565 = 0xFFFF).
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_TEXT_COLOR,
        [mem_dc, 0x00FF_FFFF],
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_BK_MODE,
        [mem_dc, 1],
    );

    // Write L"A\0" at 0x2_0000 using write_wide_z (inserts into halfwords).
    let text_ptr = 0x2_0000_u32;
    memory.write_wide_z(text_ptr, "A");

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_EXT_TEXT_OUT_W,
            [0, 0, 0, 0, 0, text_ptr, 1, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(false),
            ..
        }
    ));
    assert_eq!(
        kernel.threads.get_last_error(thread_id),
        ERROR_INVALID_HANDLE
    );
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_EXT_TEXT_OUT_W,
            [bad_hdc, 0, 0, 0, 0, text_ptr, 1, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(false),
            ..
        }
    ));
    assert_eq!(
        kernel.threads.get_last_error(thread_id),
        ERROR_INVALID_HANDLE
    );
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_EXT_TEXT_OUT_W,
            [mem_dc, 0, 0, 0, 0, 0, 1, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(false),
            ..
        }
    ));
    assert_eq!(
        kernel.threads.get_last_error(thread_id),
        ERROR_INVALID_PARAMETER
    );

    // ExtTextOutW(mem_dc, x=0, y=0, options=0, rect=0, text_ptr, count=1, dx=0)
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_EXT_TEXT_OUT_W,
            [mem_dc, 0, 0, 0, 0, text_ptr, 1, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    // Glyph row 0 of 'A' is 0x18 = bit 3 and bit 4 set from MSB.
    // With cell_h=16: glyph_row 0 → screen rows 0 and 1.
    // With cell_w=8:  glyph_col 3 → screen col 3; glyph_col 4 → screen col 4.
    // So (3, 0) and (4, 0) should be white (0xFFFF).
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 3, 0),
        0xFFFF,
        "pixel (3,0) must be text-color for 'A' glyph row 0"
    );
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 4, 0),
        0xFFFF,
        "pixel (4,0) must be text-color for 'A' glyph row 0"
    );
    // Adjacent unset pixels must remain zero (background).
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 0, 0),
        0x0000,
        "pixel (0,0) must be background (no glyph bit set)"
    );
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 7, 0),
        0x0000,
        "pixel (7,0) must be background (no glyph bit set)"
    );

    Ok(())
}

#[test]
fn coredll_raw_ext_text_out_opaque_bk_mode_fills_text_cells() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let (mem_dc, bits_ptr, stride) =
        create_selected_rgb565_dib(&table, &mut kernel, &mut memory, thread_id, 16, 16);

    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_BK_COLOR,
        [mem_dc, 0x0000_ff00],
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_TEXT_COLOR,
        [mem_dc, 0x00ff_ffff],
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_BK_MODE,
        [mem_dc, 2],
    );

    let text_ptr = 0x2_0000_u32;
    memory.write_wide_z(text_ptr, "A");

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_EXT_TEXT_OUT_W,
            [mem_dc, 0, 0, 0, 0, text_ptr, 1, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 0, 0),
        0x07e0,
        "OPAQUE background mode must fill non-glyph text-cell pixels with bk_color"
    );
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 3, 0),
        0xffff,
        "glyph pixels must still be drawn with text_color over the filled background"
    );
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 8, 0),
        0x0000,
        "pixels outside the single-character cell must remain untouched"
    );

    Ok(())
}

#[test]
fn coredll_raw_ext_text_out_honors_dc_clip_region_on_selected_dib() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let (mem_dc, bits_ptr, stride) =
        create_selected_rgb565_dib(&table, &mut kernel, &mut memory, thread_id, 16, 16);

    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_BK_COLOR,
        [mem_dc, 0x0000_ff00],
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_TEXT_COLOR,
        [mem_dc, 0x00ff_ffff],
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_BK_MODE,
        [mem_dc, 2],
    );
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_INTERSECT_CLIP_RECT,
            [mem_dc, 4, 0, 8, 16],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(2),
            ..
        }
    ));

    let text_ptr = 0x2_0000_u32;
    memory.write_wide_z(text_ptr, "A");

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_EXT_TEXT_OUT_W,
            [mem_dc, 0, 0, 0, 0, text_ptr, 1, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 3, 0),
        0x0000,
        "glyph pixels outside the DC clip must stay untouched"
    );
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 4, 0),
        0xffff,
        "glyph pixels inside the DC clip must draw"
    );
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 5, 0),
        0x07e0,
        "OPAQUE text-cell fill must also honor the DC clip"
    );
    assert_eq!(
        rgb565_at(&memory, bits_ptr, stride, 8, 0),
        0x0000,
        "the right clip edge is exclusive"
    );

    Ok(())
}

#[test]
fn coredll_raw_ext_text_out_w_draws_glyphs_into_framebuffer() -> Result<()> {
    // ExtTextOutW via a window DC renders glyphs into VirtualFramebuffer.
    // Window at (0,0,64,32) → client_to_screen origin = (0,0) → framebuffer coords = client coords.
    // Default font: height=16, ave_width=8. Glyph 'A' row 0 = 0x18 → bits 3,4 set → cols 3,4 white.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;

    let hwnd = kernel.create_window_ex_w_with_rect(
        thread_id,
        "GLYPH_FB",
        "",
        None,
        0,
        WS_VISIBLE,
        0,
        Rect::from_origin_size(0, 0, 64, 32),
    );
    let hdc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [hwnd],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(hdc),
            ..
        } => hdc,
        other => panic!("GetDC did not return a handle: {other:?}"),
    };
    // SetTextColor creates the dc_state entry so ExtTextOutW sees the white text color.
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_TEXT_COLOR,
        [hdc, 0x00FF_FFFF],
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SET_BK_MODE,
        [hdc, 1],
    );

    let text_ptr = 0x2_0000_u32;
    memory.write_wide_z(text_ptr, "A");

    let mut framebuffer = VirtualFramebuffer::new(64, 32, PixelFormat::Rgb565)?;
    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            Some(&mut framebuffer),
            thread_id,
            ORD_EXT_TEXT_OUT_W,
            [hdc, 0, 0, 0, 0, text_ptr, 1, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    let stride = framebuffer.stride();
    let pixels = framebuffer.pixels();
    let at = |col: usize, row: usize| {
        let off = row * stride + col * 2;
        u16::from_le_bytes([pixels[off], pixels[off + 1]])
    };
    // Glyph 'A' row 0 = 0x18: bits 3 and 4 (from MSB) set → cols 3 and 4 are white.
    assert_eq!(
        at(3, 0),
        0xFFFF,
        "pixel (3,0) must be white for 'A' glyph row 0"
    );
    assert_eq!(
        at(4, 0),
        0xFFFF,
        "pixel (4,0) must be white for 'A' glyph row 0"
    );
    // Adjacent unset columns must remain zero (background).
    assert_eq!(at(0, 0), 0x0000, "pixel (0,0) must be background");
    assert_eq!(at(7, 0), 0x0000, "pixel (7,0) must be background");

    Ok(())
}

