#[test]
fn coredll_raw_pat_blt_tiles_pattern_brush_on_selected_memory_dib() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let (dst_dc, dst_bits, dst_stride) =
        create_selected_rgb565_dib(&table, &mut kernel, &mut memory, thread_id, 6, 5);
    let (_pattern_dc, pattern_bitmap, pattern_bits, pattern_stride) =
        create_selected_rgb565_dib_with_bitmap(&table, &mut kernel, &mut memory, thread_id, 2, 2);
    write_rgb565(&mut memory, pattern_bits, pattern_stride, 0, 0, 0xf800);
    write_rgb565(&mut memory, pattern_bits, pattern_stride, 1, 0, 0x07e0);
    write_rgb565(&mut memory, pattern_bits, pattern_stride, 0, 1, 0x001f);
    write_rgb565(&mut memory, pattern_bits, pattern_stride, 1, 1, 0xffff);
    let pattern_brush = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_PATTERN_BRUSH,
        [pattern_bitmap],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreatePatternBrush did not return a brush: {other:?}"),
    };
    assert_ne!(pattern_brush, 0);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [dst_dc, pattern_brush],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } if handle != 0
    ));
    let old_origin = 0x1_0400;
    memory.map_words(old_origin, 2);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SET_BRUSH_ORG_EX,
            [dst_dc, 1, 1, old_origin],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert_eq!(memory.read_i32(old_origin)?, 0);
    assert_eq!(memory.read_i32(old_origin + 4)?, 0);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_PAT_BLT,
            [dst_dc, 1, 1, 3, 3, 0x00f0_0021],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 1, 1), 0xf800);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 2, 1), 0x07e0);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 1, 2), 0x001f);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 2, 2), 0xffff);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 0, 0), 0x0000);

    Ok(())
}

#[test]
fn coredll_raw_create_dib_pattern_brush_pt_uses_packed_dib() -> Result<()> {
    const DIB_RGB_COLORS: u32 = 0;
    const DIB_PAL_COLORS: u32 = 1;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;

    for usage in [DIB_PAL_COLORS, DIB_RGB_COLORS, 777] {
        assert!(matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_CREATE_DIBPATTERN_BRUSH_PT,
                [0, usage],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Handle(0),
                ..
            }
        ));
        assert_eq!(
            kernel.threads.get_last_error(thread_id),
            ERROR_INVALID_PARAMETER
        );
    }

    let (dst_dc, dst_bits, dst_stride) =
        create_selected_rgb565_dib(&table, &mut kernel, &mut memory, thread_id, 4, 4);
    let packed = 0x1_9000;
    memory.map_bytes(packed, 56);
    let mut dib = [0u8; 56];
    dib[0..4].copy_from_slice(&40u32.to_le_bytes());
    dib[4..8].copy_from_slice(&2i32.to_le_bytes());
    dib[8..12].copy_from_slice(&(-2i32).to_le_bytes());
    dib[12..14].copy_from_slice(&1u16.to_le_bytes());
    dib[14..16].copy_from_slice(&32u16.to_le_bytes());
    dib[16..20].copy_from_slice(&0u32.to_le_bytes());
    dib[40..56].copy_from_slice(&[
        0x00, 0x00, 0xff, 0xff, // red
        0x00, 0xff, 0x00, 0xff, // green
        0xff, 0x00, 0x00, 0xff, // blue
        0xff, 0xff, 0xff, 0xff, // white
    ]);
    memory.write_bytes(packed, &dib);
    memory.write_word(packed, 40);

    let pattern_brush = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_DIBPATTERN_BRUSH_PT,
        [packed, DIB_RGB_COLORS],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateDIBPatternBrushPt did not return a brush: {other:?}"),
    };
    assert_ne!(
        pattern_brush,
        0,
        "last_error={}",
        kernel.threads.get_last_error(thread_id)
    );
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [dst_dc, pattern_brush],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } if handle != 0
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_PAT_BLT,
            [dst_dc, 0, 0, 4, 4, 0x00f0_0021],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 0, 0), 0xf800);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 1, 0), 0x07e0);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 0, 1), 0x001f);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 1, 1), 0xffff);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 2, 2), 0xf800);
    assert_eq!(rgb565_at(&memory, dst_bits, dst_stride, 3, 3), 0xffff);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [dst_dc, 0x000b_5000],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } if handle == pattern_brush
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_DELETE_OBJECT,
            [pattern_brush],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    Ok(())
}

