#[test]
fn coredll_raw_origin_apis_follow_ce_viewport_contract() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let (mem_dc, bits_ptr, stride) =
        create_selected_rgb565_dib(&table, &mut kernel, &mut memory, thread_id, 16, 10);
    let point_ptr = 0x1_0200;
    let size_ptr = 0x1_0220;
    memory.map_words(point_ptr, 2);
    memory.map_words(size_ptr, 2);

    let read_pair = |memory: &TestGuestMemory, ptr| -> Result<(i32, i32)> {
        Ok((
            CoredllGuestMemory::read_u32(memory, ptr)? as i32,
            CoredllGuestMemory::read_u32(memory, ptr + 4)? as i32,
        ))
    };

    for ordinal in [
        ORD_SET_WINDOW_ORG_EX,
        ORD_GET_WINDOW_ORG_EX,
        ORD_GET_WINDOW_EXT_EX,
        ORD_OFFSET_VIEWPORT_ORG_EX,
        ORD_GET_VIEWPORT_ORG_EX,
        ORD_GET_VIEWPORT_EXT_EX,
    ] {
        assert!(
            table.resolve_ordinal(ordinal).is_some(),
            "missing CE coredll origin/ext ordinal {ordinal}"
        );
    }

    match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_VIEWPORT_ORG_EX,
        [mem_dc, point_ptr],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        } => {}
        other => panic!("GetViewportOrgEx initial state failed: {other:?}"),
    }
    assert_eq!(read_pair(&memory, point_ptr)?, (0, 0));

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_OFFSET_VIEWPORT_ORG_EX,
            [mem_dc, 3, 1, point_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert_eq!(read_pair(&memory, point_ptr)?, (0, 0));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_VIEWPORT_ORG_EX,
            [mem_dc, point_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert_eq!(read_pair(&memory, point_ptr)?, (3, 1));

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SET_WINDOW_ORG_EX,
            [mem_dc, (-4i32) as u32, (-2i32) as u32, point_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert_eq!(read_pair(&memory, point_ptr)?, (0, 0));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_WINDOW_ORG_EX,
            [mem_dc, point_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert_eq!(read_pair(&memory, point_ptr)?, (4, 2));

    for ordinal in [ORD_GET_VIEWPORT_EXT_EX, ORD_GET_WINDOW_EXT_EX] {
        assert!(matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ordinal,
                [mem_dc, size_ptr],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ));
        assert_eq!(read_pair(&memory, size_ptr)?, (16, 10));
    }

    let red_brush = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_SOLID_BRUSH,
        [0x0000_00ff],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateSolidBrush did not return a brush: {other:?}"),
    };
    let null_pen = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_STOCK_OBJECT,
        [8],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("GetStockObject(NULL_PEN) did not return a handle: {other:?}"),
    };
    for object in [red_brush, null_pen] {
        assert!(matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_SELECT_OBJECT,
                [mem_dc, object],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Handle(handle),
                ..
            } if handle != 0
        ));
    }

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_RECTANGLE,
            [mem_dc, 0, 0, 2, 2],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert_eq!(rgb565_at(&memory, bits_ptr, stride, 0, 0), 0x0000);
    assert_eq!(rgb565_at(&memory, bits_ptr, stride, 7, 3), 0xf800);

    for ordinal in [
        ORD_GET_VIEWPORT_ORG_EX,
        ORD_GET_VIEWPORT_EXT_EX,
        ORD_SET_WINDOW_ORG_EX,
        ORD_GET_WINDOW_ORG_EX,
        ORD_GET_WINDOW_EXT_EX,
        ORD_OFFSET_VIEWPORT_ORG_EX,
    ] {
        kernel.threads.set_last_error(thread_id, 0);
        assert!(matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ordinal,
                [0, 0, 0, point_ptr],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(false),
                ..
            }
        ));
        assert_eq!(
            kernel.threads.get_last_error(thread_id),
            ERROR_INVALID_HANDLE
        );
    }

    Ok(())
}

#[test]
fn coredll_raw_polyline_honors_ps_dash_on_selected_memory_dib() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let (mem_dc, bits_ptr, stride) =
        create_selected_rgb565_dib(&table, &mut kernel, &mut memory, thread_id, 16, 4);
    let points_ptr = 0x1_0200;
    let logpen_ptr = 0x1_0300;
    memory.map_bytes(points_ptr, 16);
    memory.map_bytes(logpen_ptr, 16);
    memory.write_point(points_ptr, 0, 1);
    memory.write_point(points_ptr + 8, 14, 1);
    memory.write_bytes(
        logpen_ptr,
        &[
            0x01, 0x00, 0x00, 0x00, // PS_DASH
            0x01, 0x00, 0x00, 0x00, // width 1
            0x00, 0x00, 0x00, 0x00, 0xff, 0x00, 0x00, 0x00, // red
        ],
    );
    let pen = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_PEN_INDIRECT,
        [logpen_ptr],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreatePenIndirect did not return a pen: {other:?}"),
    };
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [mem_dc, pen],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } if handle != 0
    ));

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_POLYLINE,
            [mem_dc, points_ptr, 2],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert_eq!(rgb565_at(&memory, bits_ptr, stride, 1, 1), 0xf800);
    assert_eq!(rgb565_at(&memory, bits_ptr, stride, 9, 1), 0x0000);
    assert_eq!(rgb565_at(&memory, bits_ptr, stride, 13, 1), 0xf800);

    Ok(())
}

