#[test]
fn coredll_raw_stretchblt_uses_stretch_abi_and_scales_between_memory_dcs() -> Result<()> {
    const SRCCOPY: u32 = 0x00cc_0020;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;

    let screen_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("GetDC did not return a handle: {other:?}"),
    };
    let src_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [screen_dc],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC(src) did not return a handle: {other:?}"),
    };
    let dst_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [screen_dc],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC(dst) did not return a handle: {other:?}"),
    };

    let src_info = 0x1_0000;
    let src_bits_out = 0x1_0100;
    let dst_info = 0x1_0200;
    let dst_bits_out = 0x1_0300;
    memory.map_bytes(src_info, 40);
    memory.map_words(src_bits_out, 1);
    memory.map_bytes(dst_info, 40);
    memory.map_words(dst_bits_out, 1);
    let mut src_header = [0u8; 40];
    src_header[0..4].copy_from_slice(&40u32.to_le_bytes());
    src_header[4..8].copy_from_slice(&2i32.to_le_bytes());
    src_header[8..12].copy_from_slice(&(-1i32).to_le_bytes());
    src_header[12..14].copy_from_slice(&1u16.to_le_bytes());
    src_header[14..16].copy_from_slice(&32u16.to_le_bytes());
    src_header[16..20].copy_from_slice(&0u32.to_le_bytes());
    let mut dst_header = src_header;
    dst_header[4..8].copy_from_slice(&4i32.to_le_bytes());
    memory.write_bytes(src_info, &src_header);
    memory.write_word(src_info, 40);
    memory.write_bytes(dst_info, &dst_header);
    memory.write_word(dst_info, 40);

    let src_bitmap = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_DIBSECTION,
        [screen_dc, src_info, 0, src_bits_out, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateDIBSection(src) did not return a bitmap: {other:?}"),
    };
    let dst_bitmap = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_DIBSECTION,
        [screen_dc, dst_info, 0, dst_bits_out, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateDIBSection(dst) did not return a bitmap: {other:?}"),
    };
    let src_bits = memory.read_u32(src_bits_out)?;
    let dst_bits = memory.read_u32(dst_bits_out)?;
    memory.write_bytes(
        src_bits,
        &[
            0x00, 0x00, 0xff, 0xff, // red
            0x00, 0xff, 0x00, 0xff, // green
        ],
    );
    memory.write_bytes(dst_bits, &[0; 16]);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [src_dc, src_bitmap],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } if handle != 0
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [dst_dc, dst_bitmap],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } if handle != 0
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_STRETCH_BLT,
            [dst_dc, 0, 0, 4, 1, src_dc, 0, 0, 2, 1, SRCCOPY],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert_eq!(
        memory.read_bytes(dst_bits, 16),
        vec![
            0x00, 0x00, 0xff, 0xff, // red
            0x00, 0x00, 0xff, 0xff, // red
            0x00, 0xff, 0x00, 0xff, // green
            0x00, 0xff, 0x00, 0xff, // green
        ]
    );

    Ok(())
}

#[test]
fn coredll_raw_transparent_image_copies_selected_bitmap_with_color_key() -> Result<()> {
    const MAGENTA_COLORREF: u32 = 0x00ff_00ff;
    const DISPPERF_ROP_TRANSPARENT_BLT: u32 = 0x0000_cccc;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let mut framebuffer = VirtualFramebuffer::new(4, 4, PixelFormat::Rgb565)?;
    let _ = framebuffer.take_dirty_rects();

    let screen_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("GetDC did not return a handle: {other:?}"),
    };
    let mem_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [screen_dc],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC did not return a handle: {other:?}"),
    };

    let info = 0x1_0000;
    let bits_out = 0x1_0100;
    memory.map_words(info, 10);
    memory.map_bytes(info, 40);
    memory.map_words(bits_out, 1);
    let mut header = [0u8; 40];
    header[0..4].copy_from_slice(&40u32.to_le_bytes());
    header[4..8].copy_from_slice(&2i32.to_le_bytes());
    header[8..12].copy_from_slice(&(-2i32).to_le_bytes());
    header[12..14].copy_from_slice(&1u16.to_le_bytes());
    header[14..16].copy_from_slice(&32u16.to_le_bytes());
    header[16..20].copy_from_slice(&0u32.to_le_bytes());
    memory.write_bytes(info, &header);
    memory.write_word(info, 40);
    let bitmap = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_DIBSECTION,
        [screen_dc, info, 0, bits_out, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateDIBSection did not return a bitmap: {other:?}"),
    };
    let bits_ptr = memory.read_u32(bits_out)?;
    memory.map_bytes(bits_ptr, 16);
    memory.write_bytes(
        bits_ptr,
        &[
            0xff, 0x00, 0xff, 0xff, // transparent magenta
            0x00, 0xff, 0x00, 0xff, // green
            0xff, 0x00, 0x00, 0xff, // blue
            0x00, 0x00, 0xff, 0xff, // red
        ],
    );

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [mem_dc, bitmap],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } if handle != 0
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            Some(&mut framebuffer),
            thread_id,
            ORD_TRANSPARENT_IMAGE,
            [screen_dc, 1, 1, 2, 2, mem_dc, 0, 0, 2, 2, MAGENTA_COLORREF],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    let stride = framebuffer.stride();
    let offset = |x: usize, y: usize| y * stride + x * 2;
    assert_eq!(
        &framebuffer.pixels()[offset(1, 1)..offset(1, 1) + 2],
        &[0x00, 0x00]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(2, 1)..offset(2, 1) + 2],
        &[0xe0, 0x07]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(1, 2)..offset(1, 2) + 2],
        &[0x1f, 0x00]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(2, 2)..offset(2, 2) + 2],
        &[0x00, 0xf8]
    );
    assert_eq!(
        framebuffer.dirty_rects(),
        &[FramebufferRect::new(1, 1, 2, 2)]
    );
    let timing = kernel.display_perf_timing_bytes();
    assert_eq!(
        u32::from_le_bytes(timing[0..4].try_into().unwrap()),
        DISPPERF_ROP_TRANSPARENT_BLT
    );
    assert_eq!(u32::from_le_bytes(timing[4..8].try_into().unwrap()), 1);
    assert_eq!(u32::from_le_bytes(timing[8..12].try_into().unwrap()), 1);
    assert_eq!(u32::from_le_bytes(timing[12..16].try_into().unwrap()), 0);

    Ok(())
}

#[test]
fn coredll_raw_transparent_image_copies_between_framebuffer_hdc_with_color_key() -> Result<()> {
    const BLACK_COLORREF: u32 = 0x0000_0000;
    const WHITE_COLORREF: u32 = 0x00ff_ffff;
    const BLACKNESS: u32 = 0x0000_0042;
    const WHITENESS: u32 = 0x00ff_0062;
    const DISPPERF_ROP_TRANSPARENT_BLT: u32 = 0x0000_cccc;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let mut framebuffer = VirtualFramebuffer::new(2, 2, PixelFormat::Rgb565)?;
    let _ = framebuffer.take_dirty_rects();

    let screen_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("GetDC did not return a handle: {other:?}"),
    };

    for (src_rop, dst_rop, transparent, expected) in [
        (WHITENESS, BLACKNESS, WHITE_COLORREF, 0x0000),
        (WHITENESS, BLACKNESS, BLACK_COLORREF, 0xffff),
        (BLACKNESS, WHITENESS, BLACK_COLORREF, 0xffff),
        (BLACKNESS, WHITENESS, WHITE_COLORREF, 0x0000),
    ] {
        assert!(matches!(
            table.dispatch_raw_ordinal_with_framebuffer(
                &mut kernel,
                &mut memory,
                Some(&mut framebuffer),
                thread_id,
                ORD_PAT_BLT,
                [screen_dc, 0, 0, 1, 1, src_rop],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ));
        assert!(matches!(
            table.dispatch_raw_ordinal_with_framebuffer(
                &mut kernel,
                &mut memory,
                Some(&mut framebuffer),
                thread_id,
                ORD_PAT_BLT,
                [screen_dc, 0, 1, 1, 1, dst_rop],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ));
        assert!(matches!(
            table.dispatch_raw_ordinal_with_framebuffer(
                &mut kernel,
                &mut memory,
                Some(&mut framebuffer),
                thread_id,
                ORD_TRANSPARENT_IMAGE,
                [screen_dc, 0, 1, 1, 1, screen_dc, 0, 0, 1, 1, transparent],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ));
        assert_eq!(framebuffer_rgb565_at(&framebuffer, 0, 1), expected);
    }

    let timing = kernel.display_perf_timing_bytes();
    let transparent_timing = timing
        .chunks_exact(64)
        .find(|row| {
            u32::from_le_bytes(row[0..4].try_into().unwrap()) == DISPPERF_ROP_TRANSPARENT_BLT
        })
        .expect("transparent blit timing row should be recorded");
    assert_eq!(
        u32::from_le_bytes(transparent_timing[4..8].try_into().unwrap()),
        4
    );
    assert_eq!(
        u32::from_le_bytes(transparent_timing[40..44].try_into().unwrap()),
        4,
        "PARAM_SRCINVIDMEM should count same-framebuffer TransparentImage sources"
    );
    assert_eq!(
        u32::from_le_bytes(transparent_timing[44..48].try_into().unwrap()),
        4,
        "PARAM_DESTINVIDMEM should count same-framebuffer TransparentImage destinations"
    );
    assert_eq!(
        u32::from_le_bytes(transparent_timing[60..64].try_into().unwrap()),
        4,
        "PARAM_TRANSPARENT should count TransparentImage rows"
    );

    Ok(())
}

#[test]
fn coredll_raw_transparent_image_mirrors_negative_extents_on_framebuffer_hdc() -> Result<()> {
    const MAGENTA_COLORREF: u32 = 0x00ff_00ff;
    const RED565: u16 = 0xf800;
    const MAGENTA565: u16 = 0xf81f;
    const WHITE565: u16 = 0xffff;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let mut framebuffer = VirtualFramebuffer::new(4, 2, PixelFormat::Rgb565)?;

    let screen_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("GetDC did not return a handle: {other:?}"),
    };

    for y in 0..2 {
        let row = y * framebuffer.stride();
        framebuffer.pixels_mut()[row..row + 2].copy_from_slice(&RED565.to_le_bytes());
        framebuffer.pixels_mut()[row + 2..row + 4].copy_from_slice(&MAGENTA565.to_le_bytes());
        framebuffer.pixels_mut()[row + 4..row + 6].copy_from_slice(&WHITE565.to_le_bytes());
        framebuffer.pixels_mut()[row + 6..row + 8].copy_from_slice(&WHITE565.to_le_bytes());
    }
    let _ = framebuffer.take_dirty_rects();

    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            Some(&mut framebuffer),
            thread_id,
            ORD_TRANSPARENT_IMAGE,
            [
                screen_dc,
                2,
                0,
                2,
                1,
                screen_dc,
                2,
                0,
                (-2i32) as u32,
                1,
                MAGENTA_COLORREF,
            ],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            Some(&mut framebuffer),
            thread_id,
            ORD_TRANSPARENT_IMAGE,
            [
                screen_dc,
                4,
                1,
                (-2i32) as u32,
                1,
                screen_dc,
                0,
                1,
                2,
                1,
                MAGENTA_COLORREF,
            ],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert_eq!(framebuffer_rgb565_at(&framebuffer, 2, 0), WHITE565);
    assert_eq!(framebuffer_rgb565_at(&framebuffer, 3, 0), RED565);
    assert_eq!(framebuffer_rgb565_at(&framebuffer, 2, 1), WHITE565);
    assert_eq!(framebuffer_rgb565_at(&framebuffer, 3, 1), RED565);
    assert_eq!(
        framebuffer.dirty_rects(),
        &[
            FramebufferRect::new(2, 0, 2, 1),
            FramebufferRect::new(2, 1, 2, 1),
        ]
    );
    assert_eq!(kernel.threads.get_last_error(thread_id), 0);

    Ok(())
}

#[test]
fn coredll_raw_transparent_image_composites_between_memory_dcs() -> Result<()> {
    const MAGENTA_COLORREF: u32 = 0x00ff_00ff;
    const SRCCOPY: u32 = 0x00cc_0020;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let mut framebuffer = VirtualFramebuffer::new(4, 4, PixelFormat::Rgb565)?;
    let _ = framebuffer.take_dirty_rects();

    let screen_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("GetDC did not return a handle: {other:?}"),
    };
    let src_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [screen_dc],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC(src) did not return a handle: {other:?}"),
    };
    let dst_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [screen_dc],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC(dst) did not return a handle: {other:?}"),
    };

    let info = 0x1_0000;
    let src_bits_out = 0x1_0100;
    let dst_bits_out = 0x1_0110;
    memory.map_words(info, 10);
    memory.map_bytes(info, 40);
    memory.map_words(src_bits_out, 1);
    memory.map_words(dst_bits_out, 1);
    let mut header = [0u8; 40];
    header[0..4].copy_from_slice(&40u32.to_le_bytes());
    header[4..8].copy_from_slice(&2i32.to_le_bytes());
    header[8..12].copy_from_slice(&(-2i32).to_le_bytes());
    header[12..14].copy_from_slice(&1u16.to_le_bytes());
    header[14..16].copy_from_slice(&32u16.to_le_bytes());
    header[16..20].copy_from_slice(&0u32.to_le_bytes());
    memory.write_bytes(info, &header);
    memory.write_word(info, 40);

    let src_bitmap = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_DIBSECTION,
        [screen_dc, info, 0, src_bits_out, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateDIBSection(src) did not return a bitmap: {other:?}"),
    };
    let dst_bitmap = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_DIBSECTION,
        [screen_dc, info, 0, dst_bits_out, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateDIBSection(dst) did not return a bitmap: {other:?}"),
    };
    let src_bits = memory.read_u32(src_bits_out)?;
    let dst_bits = memory.read_u32(dst_bits_out)?;
    memory.map_bytes(src_bits, 16);
    memory.map_bytes(dst_bits, 16);
    memory.write_bytes(
        src_bits,
        &[
            0xff, 0x00, 0xff, 0xff, // transparent magenta
            0x00, 0xff, 0x00, 0xff, // green
            0xff, 0x00, 0x00, 0xff, // blue
            0x00, 0x00, 0xff, 0xff, // red
        ],
    );
    memory.write_bytes(dst_bits, &[0xff; 16]);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [src_dc, src_bitmap],
        ),
        CoredllDispatch::Returned { .. }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_OBJECT,
            [dst_dc, dst_bitmap],
        ),
        CoredllDispatch::Returned { .. }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            None,
            thread_id,
            ORD_TRANSPARENT_IMAGE,
            [dst_dc, 0, 0, 2, 2, src_dc, 0, 0, 2, 2, MAGENTA_COLORREF],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            Some(&mut framebuffer),
            thread_id,
            ORD_BIT_BLT,
            [screen_dc, 1, 1, 2, 2, dst_dc, 0, 0, SRCCOPY],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    let stride = framebuffer.stride();
    let offset = |x: usize, y: usize| y * stride + x * 2;
    assert_eq!(
        &framebuffer.pixels()[offset(1, 1)..offset(1, 1) + 2],
        &[0xff, 0xff]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(2, 1)..offset(2, 1) + 2],
        &[0xe0, 0x07]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(1, 2)..offset(1, 2) + 2],
        &[0x1f, 0x00]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(2, 2)..offset(2, 2) + 2],
        &[0x00, 0xf8]
    );

    Ok(())
}

#[test]
fn coredll_raw_transparent_image_mirrors_negative_extents_between_selected_dibs() -> Result<()> {
    const MAGENTA_COLORREF: u32 = 0x00ff_00ff;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;

    let (src_dc, _src_bitmap, src_bits, src_stride) =
        create_selected_32bpp_dib_with_bitmap(&table, &mut kernel, &mut memory, thread_id, 2, 2);
    let (dst_dc, _dst_bitmap, dst_bits, dst_stride) =
        create_selected_32bpp_dib_with_bitmap(&table, &mut kernel, &mut memory, thread_id, 2, 2);
    memory.write_bytes(
        src_bits,
        &[
            0x00, 0x00, 0xff, 0xff, // red
            0x00, 0xff, 0x00, 0xff, // green
            0xff, 0x00, 0x00, 0xff, // blue
            0xff, 0x00, 0xff, 0xff, // transparent magenta
        ],
    );
    memory.write_bytes(dst_bits, &[0xff; 16]);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            None,
            thread_id,
            ORD_TRANSPARENT_IMAGE,
            [
                dst_dc,
                2,
                2,
                (-2i32) as u32,
                (-2i32) as u32,
                src_dc,
                2,
                2,
                (-2i32) as u32,
                (-2i32) as u32,
                MAGENTA_COLORREF,
            ],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert_eq!(kernel.threads.get_last_error(thread_id), 0);
    assert_eq!(
        memory.read_bytes(dst_bits, (dst_stride * 2) as usize),
        vec![
            0x00, 0x00, 0xff, 0xff, // red
            0x00, 0xff, 0x00, 0xff, // green
            0xff, 0x00, 0x00, 0xff, // blue
            0xff, 0xff, 0xff, 0xff, // skipped transparent magenta
        ]
    );
    assert_eq!(src_stride, 8);
    assert_eq!(dst_stride, 8);

    Ok(())
}

#[test]
fn coredll_raw_direct_dib_calls_paint_attached_framebuffer() -> Result<()> {
    const DIB_RGB_COLORS: u32 = 0;
    const SRCCOPY: u32 = 0x00cc_0020;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 9;
    let mut framebuffer = VirtualFramebuffer::new(4, 4, PixelFormat::Rgb565)?;
    let _ = framebuffer.take_dirty_rects();

    let screen_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("GetDC did not return a handle: {other:?}"),
    };

    let info = 0x1_0000;
    let bits = 0x1_0100;
    memory.map_words(info, 10);
    memory.map_bytes(info, 40);
    memory.map_bytes(bits, 16);
    let mut header = [0u8; 40];
    header[0..4].copy_from_slice(&40u32.to_le_bytes());
    header[4..8].copy_from_slice(&2i32.to_le_bytes());
    header[8..12].copy_from_slice(&(-2i32).to_le_bytes());
    header[12..14].copy_from_slice(&1u16.to_le_bytes());
    header[14..16].copy_from_slice(&32u16.to_le_bytes());
    header[16..20].copy_from_slice(&0u32.to_le_bytes());
    memory.write_bytes(info, &header);
    memory.write_word(info, 40);
    memory.write_bytes(
        bits,
        &[
            0x00, 0x00, 0xff, 0xff, // red
            0x00, 0xff, 0x00, 0xff, // green
            0xff, 0x00, 0x00, 0xff, // blue
            0xff, 0xff, 0xff, 0xff, // white
        ],
    );

    let stretch_result = table.dispatch_raw_ordinal_with_framebuffer(
        &mut kernel,
        &mut memory,
        Some(&mut framebuffer),
        thread_id,
        ORD_STRETCH_DIBITS,
        [
            screen_dc,
            1,
            0,
            2,
            2,
            0,
            0,
            2,
            2,
            bits,
            info,
            DIB_RGB_COLORS,
            SRCCOPY,
        ],
    );
    assert!(
        matches!(
            stretch_result,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(2),
                ..
            }
        ),
        "unexpected StretchDIBits result: {stretch_result:?}, hdc=0x{screen_dc:08x}, last_error={}",
        kernel.threads.get_last_error(thread_id)
    );

    let stride = framebuffer.stride();
    let offset = |x: usize, y: usize| y * stride + x * 2;
    assert_eq!(
        &framebuffer.pixels()[offset(1, 0)..offset(1, 0) + 2],
        &[0x00, 0xf8]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(2, 0)..offset(2, 0) + 2],
        &[0xe0, 0x07]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(1, 1)..offset(1, 1) + 2],
        &[0x1f, 0x00]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(2, 1)..offset(2, 1) + 2],
        &[0xff, 0xff]
    );
    assert_eq!(
        framebuffer.dirty_rects(),
        &[FramebufferRect::new(1, 0, 2, 2)]
    );

    let _ = framebuffer.take_dirty_rects();
    assert!(matches!(
        table.dispatch_raw_ordinal_with_framebuffer(
            &mut kernel,
            &mut memory,
            Some(&mut framebuffer),
            thread_id,
            ORD_SET_DIBITS_TO_DEVICE,
            [
                screen_dc,
                0,
                2,
                2,
                2,
                0,
                0,
                0,
                2,
                bits,
                info,
                DIB_RGB_COLORS
            ],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(2),
            ..
        }
    ));
    assert_eq!(
        &framebuffer.pixels()[offset(0, 2)..offset(0, 2) + 2],
        &[0x00, 0xf8]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(1, 2)..offset(1, 2) + 2],
        &[0xe0, 0x07]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(0, 3)..offset(0, 3) + 2],
        &[0x1f, 0x00]
    );
    assert_eq!(
        &framebuffer.pixels()[offset(1, 3)..offset(1, 3) + 2],
        &[0xff, 0xff]
    );
    assert_eq!(
        framebuffer.dirty_rects(),
        &[FramebufferRect::new(0, 2, 2, 2)]
    );

    Ok(())
}

