    assert_eq!(memory.read_i32(dx_ptr + 4)?, 11);
    assert_eq!(memory.read_i32(dx_ptr + 8)?, 14);
    assert_eq!(memory.read_i32(dx_ptr + 12)?, 17);
    assert_eq!(memory.read_i32(size_ptr)?, 17);
    assert_eq!(memory.read_i32(size_ptr + 4)?, 16);

