#[test]
fn coredll_raw_bring_window_to_top_updates_z_order_and_activation() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 34;
    let msg_ptr = 0x7c00;
    memory.map_words(msg_ptr, 7);

    let first = kernel.create_window_ex_w(thread_id, "ZFIRST", "", None, 0, 0, 0);
    let second = kernel.create_window_ex_w(thread_id, "ZSECOND", "", None, 0, 0, 0);
    let third = kernel.create_window_ex_w(thread_id, "ZTHIRD", "", None, 0, 0, 0);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_WINDOW,
            [first, GW_HWNDFIRST],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(hwnd),
            ..
        } if hwnd == third
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_BRING_WINDOW_TO_TOP,
            [third],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_WINDOW,
            [first, GW_HWNDFIRST],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(hwnd),
            ..
        } if hwnd == third
    ));
    assert_next_message(
        &table,
        &mut kernel,
        &mut memory,
        thread_id,
        msg_ptr,
        third,
        WM_ACTIVATE,
        WA_ACTIVE,
        0,
    );

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_BRING_WINDOW_TO_TOP,
            [second],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_WINDOW,
            [first, GW_HWNDFIRST],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(hwnd),
            ..
        } if hwnd == second
    ));
    assert_next_message(
        &table,
        &mut kernel,
        &mut memory,
        thread_id,
        msg_ptr,
        third,
        WM_ACTIVATE,
        WA_INACTIVE,
        second,
    );
    assert_next_message(
        &table,
        &mut kernel,
        &mut memory,
        thread_id,
        msg_ptr,
        second,
        WM_ACTIVATE,
        WA_ACTIVE,
        third,
    );

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_BRING_WINDOW_TO_TOP,
            [0xffff_ffff],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(false),
            ..
        }
    ));

    Ok(())
}

#[test]
fn coredll_raw_queue_status_tracks_thread_posts_and_paint() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 6;
    let msg_ptr = 0x9800;
    memory.map_words(msg_ptr, 7);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_QUEUE_STATUS,
            [QS_POSTMESSAGE],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(0),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_POST_THREAD_MESSAGE_W,
            [thread_id, WM_USER + 61, 0x61, 0x62],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_QUEUE_STATUS,
            [QS_POSTMESSAGE],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(v),
            ..
        } if v == ((QS_POSTMESSAGE << 16) | QS_POSTMESSAGE)
    ));
    assert_next_message(
        &table,
        &mut kernel,
        &mut memory,
        thread_id,
        msg_ptr,
        0,
        WM_USER + 61,
        0x61,
        0x62,
    );
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_QUEUE_STATUS,
            [QS_POSTMESSAGE],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(0),
            ..
        }
    ));

    let hwnd = kernel.create_window_ex_w(thread_id, "PAINTSTATUS", "", None, 0, WS_VISIBLE, 0);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_QUEUE_STATUS,
            [QS_PAINT],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(v),
            ..
        } if v == ((QS_PAINT << 16) | QS_PAINT)
    ));
    assert_next_message(
        &table,
        &mut kernel,
        &mut memory,
        thread_id,
        msg_ptr,
        hwnd,
        WM_PAINT,
        0,
        0,
    );

    Ok(())
}

