#[test]
fn coredll_raw_translate_message_western_layout_dead_keys() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 41;
    let msg_ptr = 0x2_0000;
    memory.map_words(msg_ptr, 7);
    let hwnd = kernel.create_window_ex_w(thread_id, "DEADKEY_OWNER", "", None, 0, 0, 0);

    // Switch to German QWERTZ (0x0407) layout.
    kernel.gwe.activate_keyboard_layout(0x0407);

    let translate = |kernel: &mut CeKernel,
                     memory: &mut TestGuestMemory,
                     vkey: u32,
                     shift: bool|
     -> CoredllDispatch {
        if shift {
            kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYDOWN, VK_LSHIFT, 0);
        }
        write_raw_message(memory, msg_ptr, hwnd, WM_KEYDOWN, vkey, vkey + 0x100).unwrap();
        let r = table.dispatch_raw_ordinal_with_memory(
            kernel,
            memory,
            thread_id,
            ORD_TRANSLATE_MESSAGE,
            [msg_ptr],
        );
        if shift {
            kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYUP, VK_LSHIFT, 0);
        }
        r
    };

    // --- German QWERTZ dead circumflex (VK_OEM_3 = 0xC0 unshifted → '^') ---
    // Press ^: should post WM_DEADCHAR and store the pending dead key.
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0xc0, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let deadchar_msg = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_DEADCHAR,
            WM_DEADCHAR,
            PeekFlags::REMOVE,
        )
        .expect("dead circumflex should post WM_DEADCHAR");
    assert_eq!(deadchar_msg.wparam, 0x5e, "dead char should be '^'");
    assert!(
        kernel.gwe.dead_key().is_some(),
        "dead key should be pending"
    );

    // Press 'e' (VK 0x45): dead circumflex + 'e' → 'ê' (0x00EA).
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0x45, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(
        kernel.gwe.dead_key().is_none(),
        "dead key should be cleared after composition"
    );
    let char_msg = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("^ + e should post WM_CHAR(ê)");
    assert_eq!(char_msg.wparam, 0x00ea, "circumflex + e → ê");

    // --- German QWERTZ dead acute (VK_OEM_PLUS = 0xBB unshifted → '´') ---
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0xbb, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let _ = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_DEADCHAR,
            WM_DEADCHAR,
            PeekFlags::REMOVE,
        )
        .expect("dead acute should post WM_DEADCHAR");

    // Press 'u' → 'ú' (0x00FA).
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0x55, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let char_msg = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("´ + u should post WM_CHAR(ú)");
    assert_eq!(char_msg.wparam, 0x00fa, "acute + u → ú");

    // --- No composition: dead grave + 'z' → literal ` then z ---
    // Dead grave via VK_OEM_PLUS shifted (0xBB + shift → '`')
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0xbb, true),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let _ = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_DEADCHAR,
            WM_DEADCHAR,
            PeekFlags::REMOVE,
        )
        .expect("dead grave should post WM_DEADCHAR");

    // Press 'z' on QWERTZ → 'y' character (0x79). Dead grave + 'y' has no composition.
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0x5a, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let dead_literal = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("no-compose: should post WM_CHAR(grave)");
    assert_eq!(dead_literal.wparam, 0x60, "no-compose: literal grave first");
    let base_char = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("no-compose: should post WM_CHAR(y)");
    assert_eq!(
        base_char.wparam, 0x79,
        "no-compose: base char 'y' after dead grave"
    );

    // --- French AZERTY (0x040C): dead diaeresis (VK_OEM_4 = 0xDB + shift → '¨') ---
    kernel.gwe.activate_keyboard_layout(0x040C);
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0xdb, true),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let _ = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_DEADCHAR,
            WM_DEADCHAR,
            PeekFlags::REMOVE,
        )
        .expect("dead diaeresis should post WM_DEADCHAR");

    // Press 'o' on AZERTY → 'o' (VK_O = 0x4F). Dead diaeresis + 'o' → 'ö' (0x00F6).
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0x4f, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let char_msg = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("¨ + o should post WM_CHAR(ö)");
    assert_eq!(char_msg.wparam, 0x00f6, "diaeresis + o → ö");

    // --- Space after dead key emits the dead char literally ---
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0xdb, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let _ = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_DEADCHAR,
            WM_DEADCHAR,
            PeekFlags::REMOVE,
        )
        .expect("dead circumflex should post WM_DEADCHAR");
    // Press space: ^ + space → literal '^'
    assert!(matches!(
        translate(&mut kernel, &mut memory, 0x20, false),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    let space_result = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("dead ^ + space should post WM_CHAR(^)");
    assert_eq!(space_result.wparam, 0x5e, "dead ^ + space → literal '^'");

    Ok(())
}

#[test]
fn coredll_raw_keybd_vkey_to_unicode_honors_active_layout() -> Result<()> {
    // Verify that KeybdVKeyToUnicode uses the active keyboard layout for OEM keys.
    // VK_OEM_4 (0xDB):
    //   - US layout (0x0409): '[' (0x5B), not a dead key.
    //   - AZERTY (0x040C): '^' (0x5E), dead key.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 42;
    let buf_ptr: u32 = 0x1_0000; // WCHAR output — must be halfword-mapped
    let flags_ptr: u32 = 0x1_0004; // u32 flags output — word-mapped
    memory.map_halfwords(buf_ptr, 1);
    memory.map_words(flags_ptr, 1);

    // args: vk=0xDB, scan=0, key_state_ptr=0, buf_ptr, buf_size=1, flags_ptr
    let call = |kernel: &mut CeKernel, memory: &mut TestGuestMemory| {
        table.dispatch_raw_ordinal_with_memory(
            kernel,
            memory,
            thread_id,
            ORD_KEYBD_VKEY_TO_UNICODE,
            [0xDB_u32, 0, 0, buf_ptr, 1, flags_ptr],
        )
    };

    // --- US layout (default, 0x0409) → '[' (0x5B), flags = 0 ---
    let result = call(&mut kernel, &mut memory);
    assert!(
        matches!(
            result,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(1),
                ..
            }
        ),
        "US layout: should return 1 char written"
    );
    let char_us = memory.read_u16(buf_ptr)?;
    assert_eq!(char_us, 0x5B, "US VK_OEM_4 → '[' (0x5B)");
    let flags_us = memory.read_u32(flags_ptr)?;
    assert_eq!(flags_us, 0, "US '[' is not a dead key");

    // --- AZERTY (0x040C) → '^' (0x5E), flags = 1 (dead key) ---
    kernel.gwe.activate_keyboard_layout(0x040C);
    let result = call(&mut kernel, &mut memory);
    assert!(
        matches!(
            result,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(1),
                ..
            }
        ),
        "AZERTY layout: should return 1 char written"
    );
    let char_azerty = memory.read_u16(buf_ptr)?;
    assert_eq!(char_azerty, 0x5E, "AZERTY VK_OEM_4 → '^' (0x5E)");
    let flags_azerty = memory.read_u32(flags_ptr)?;
    assert_eq!(flags_azerty, 1, "AZERTY '^' is a dead key (bit 0 set)");

    Ok(())
}

#[test]
fn coredll_raw_map_virtual_key_vk_to_char_honors_active_layout() -> Result<()> {
    // MapVirtualKeyW(MAPVK_VK_TO_CHAR=2) must use the active keyboard layout.
    // VK_OEM_4 (0xDB):
    //   - US layout (0x0409): '[' (0x5B), not dead → returns 0x5B.
    //   - AZERTY (0x040C): '^' (0x5E), dead key  → returns 0x8000005E (bit 31 set).
    //   - QWERTZ (0x0407): VK_OEM_3 (0xC0) unshifted → '^' dead → 0x8000005E.
    const MAPVK_VK_TO_CHAR: u32 = 2;
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 43;

    let mvk = |kernel: &mut CeKernel, memory: &mut TestGuestMemory, vk: u32| {
        table.dispatch_raw_ordinal_with_memory(
            kernel,
            memory,
            thread_id,
            ORD_MAP_VIRTUAL_KEY_W,
            [vk, MAPVK_VK_TO_CHAR],
        )
    };

    // US layout (default 0x0409): VK_OEM_4 → '[' (0x5B).
    assert!(
        matches!(
            mvk(&mut kernel, &mut memory, 0xDB),
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0x5B),
                ..
            }
        ),
        "US VK_OEM_4 MAPVK_VK_TO_CHAR → 0x5B"
    );

    // AZERTY (0x040C): VK_OEM_4 → '^' dead key → 0x8000005E.
    kernel.gwe.activate_keyboard_layout(0x040C);
    assert!(
        matches!(
            mvk(&mut kernel, &mut memory, 0xDB),
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0x8000_005E),
                ..
            }
        ),
        "AZERTY VK_OEM_4 MAPVK_VK_TO_CHAR → 0x8000005E (dead '^')"
    );

    // AZERTY: letter VK 'A' (0x41) → 'q' (AZERTY remaps A key to q).
    assert!(
        matches!(
            mvk(&mut kernel, &mut memory, 0x41),
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0x71),
                ..
            }
        ),
        "AZERTY VK_A MAPVK_VK_TO_CHAR → 'q' (0x71)"
    );

    // QWERTZ (0x0407): VK_OEM_3 (0xC0) → '^' dead key → 0x8000005E.
    kernel.gwe.activate_keyboard_layout(0x0407);
    assert!(
        matches!(
            mvk(&mut kernel, &mut memory, 0xC0),
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0x8000_005E),
                ..
            }
        ),
        "QWERTZ VK_OEM_3 MAPVK_VK_TO_CHAR → 0x8000005E (dead '^')"
    );

    Ok(())
}

#[test]
fn coredll_raw_translate_accelerator_wm_keydown_uses_active_layout() -> Result<()> {
    // Non-FVIRTKEY character accelerators matched against WM_KEYDOWN must use the
    // active keyboard layout to translate VK → char before comparing.
    // AZERTY: VK_Z (0x5A) → 'w' (AZERTY remaps Z key to w/W).
    // US layout: VK_Z → 'z', so a 'w' accelerator should NOT fire.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 44_u32;
    let msg_ptr = 0x1_9000_u32;
    memory.map_words(msg_ptr, 7);
    let hwnd = kernel.create_window_ex_w(thread_id, "ACCEL_LAYOUT", "", None, 0, 0, 0);

    // Accelerator table: single non-FVIRTKEY entry for 'w' (0x77).
    let accel = kernel.resources.create_accelerator(
        0,
        ResourceId::Integer(900),
        None,
        vec![AcceleratorEntry {
            flags: 0,
            key: u16::from(b'w'),
            command: 9001,
        }],
    );

    // --- US layout (default): VK_Z → 'z', NOT 'w' → no match.
    write_raw_message(&mut memory, msg_ptr, hwnd, WM_KEYDOWN, 0x5A, 0)?;
    assert!(
        matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_TRANSLATE_ACCELERATOR_W,
                [hwnd, accel, msg_ptr],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0),
                ..
            }
        ),
        "US layout: VK_Z should not match 'w' char accelerator"
    );

    // --- AZERTY (0x040C): VK_Z → 'w' → matches char accel 9001.
    kernel.gwe.activate_keyboard_layout(0x040C);
    write_raw_message(&mut memory, msg_ptr, hwnd, WM_KEYDOWN, 0x5A, 0)?;
    assert!(
        matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_TRANSLATE_ACCELERATOR_W,
                [hwnd, accel, msg_ptr],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::U32(1),
                ..
            }
        ),
        "AZERTY: VK_Z WM_KEYDOWN should match 'w' char accelerator"
    );
    let cmd = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_COMMAND,
            WM_COMMAND,
            PeekFlags::REMOVE,
        )
        .expect("AZERTY VK_Z → 'w' should post WM_COMMAND 9001");
    assert_eq!(cmd.wparam & 0xFFFF, 9001, "command ID should be 9001");
    assert_eq!(
        cmd.wparam >> 16,
        1,
        "HIWORD should be 1 (accelerator notification)"
    );

    Ok(())
}

#[test]
fn coredll_raw_translate_message_syskeydown_uses_active_layout() -> Result<()> {
    // WM_SYSKEYDOWN (Alt+key) on a Western layout must translate VK using the
    // layout-specific table and post WM_SYSCHAR with the layout character, not
    // the US-layout character.
    // AZERTY (0x040C): Alt+VK_Z (0x5A) → WM_SYSCHAR('w', 0x77).
    // US layout: Alt+VK_Z → WM_SYSCHAR('z', 0x7A).
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 45_u32;
    let msg_ptr = 0x2_1000_u32;
    memory.map_words(msg_ptr, 7);
    let hwnd = kernel.create_window_ex_w(thread_id, "SYSKEYDOWN_LAYOUT", "", None, 0, 0, 0);

    // Set Alt down (required for WM_SYSKEYDOWN).
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYDOWN, VK_MENU, 0);

    // --- US layout (default): Alt+VK_Z → WM_SYSCHAR('z', 0x7A).
    write_raw_message(&mut memory, msg_ptr, hwnd, WM_SYSKEYDOWN, 0x5A, 0)?;
    assert!(
        matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_TRANSLATE_MESSAGE,
                [msg_ptr],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ),
        "US layout: WM_SYSKEYDOWN VK_Z should produce WM_SYSCHAR"
    );
    let syschar = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_SYSCHAR,
            WM_SYSCHAR,
            PeekFlags::REMOVE,
        )
        .expect("US Alt+VK_Z should post WM_SYSCHAR");
    assert_eq!(syschar.wparam, 0x7A, "US Alt+VK_Z → WM_SYSCHAR('z', 0x7A)");

    // --- AZERTY (0x040C): Alt+VK_Z → AZERTY maps Z key to 'w' → WM_SYSCHAR('w', 0x77).
    kernel.gwe.activate_keyboard_layout(0x040C);
    write_raw_message(&mut memory, msg_ptr, hwnd, WM_SYSKEYDOWN, 0x5A, 0)?;
    assert!(
        matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_TRANSLATE_MESSAGE,
                [msg_ptr],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ),
        "AZERTY: WM_SYSKEYDOWN VK_Z should produce WM_SYSCHAR"
    );
    let syschar = kernel
        .gwe
        .peek_message_filtered(
            thread_id,
            Some(hwnd),
            WM_SYSCHAR,
            WM_SYSCHAR,
            PeekFlags::REMOVE,
        )
        .expect("AZERTY Alt+VK_Z should post WM_SYSCHAR");
    assert_eq!(
        syschar.wparam, 0x77,
        "AZERTY Alt+VK_Z → WM_SYSCHAR('w', 0x77)"
    );

    Ok(())
}

#[test]
fn coredll_raw_enum_windows_raw_path_returns_true() -> Result<()> {
    // Raw (non-Unicorn) EnumWindows: cannot invoke guest callbacks without Unicorn,
    // so the raw path performs an empty enumeration and always returns TRUE.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 1;

    // With no windows: returns TRUE.
    assert!(
        matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_ENUM_WINDOWS,
                [0u32, 0u32],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ),
        "EnumWindows with no windows returns TRUE"
    );

    // Create a visible top-level window using the kernel helper.
    let hwnd = kernel.create_window_ex_w_with_rect(
        thread_id,
        "EnumTest",
        "Test Window",
        None,
        0,
        WS_VISIBLE,
        0,
        Rect::from_origin_size(0, 0, 100, 100),
    );
    assert_ne!(hwnd, 0);

    // With a window present, raw path still returns TRUE (callback is not invoked without Unicorn).
    // A fake guest pointer 0xDEAD_0001 represents what a real Unicorn-path callback would look like.
    assert!(
        matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ORD_ENUM_WINDOWS,
                [0xDEAD_0001u32, 0xABCDu32],
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ),
        "EnumWindows in raw path returns TRUE without invoking callback"
    );

    Ok(())
}

#[test]
fn coredll_raw_gwe_wm_seticon_and_geticon() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 1;

    let hwnd = kernel.create_window_ex_w_with_rect(
        thread_id,
        "TestClass",
        "Icon Test",
        None,
        0,
        WS_VISIBLE,
        0,
        Rect::from_origin_size(0, 0, 100, 100),
    );
    assert_ne!(hwnd, 0);

    // WM_GETICON on a fresh window returns 0 (no icon set, no class icon).
    let get_small = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SEND_MESSAGE_W,
        [hwnd, WM_GETICON, ICON_SMALL, 0u32],
    );
    assert!(
        matches!(
            get_small,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0),
                ..
            }
        ),
        "WM_GETICON ICON_SMALL on fresh window returns 0"
    );

    // WM_SETICON ICON_SMALL: returns previous (0), then stores 0xBEEF.
    let set_small = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SEND_MESSAGE_W,
        [hwnd, WM_SETICON, ICON_SMALL, 0xBEEFu32],
    );
    assert!(
        matches!(
            set_small,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0),
                ..
            }
        ),
        "WM_SETICON ICON_SMALL returns previous icon (0)"
    );

    // WM_GETICON ICON_SMALL now returns 0xBEEF.
    let get_small2 = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SEND_MESSAGE_W,
        [hwnd, WM_GETICON, ICON_SMALL, 0u32],
    );
    assert!(
        matches!(
            get_small2,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0xBEEF),
                ..
            }
        ),
        "WM_GETICON ICON_SMALL returns stored icon 0xBEEF"
    );

    // WM_SETICON ICON_BIG: stores 0xCAFE, old value was 0.
    let set_big = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SEND_MESSAGE_W,
        [hwnd, WM_SETICON, ICON_BIG, 0xCAFEu32],
    );
    assert!(
        matches!(
            set_big,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0),
                ..
            }
        ),
        "WM_SETICON ICON_BIG returns previous icon (0)"
    );

    // WM_GETICON ICON_BIG returns 0xCAFE; ICON_SMALL still 0xBEEF.
    let get_big = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SEND_MESSAGE_W,
        [hwnd, WM_GETICON, ICON_BIG, 0u32],
    );
    assert!(
        matches!(
            get_big,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0xCAFE),
                ..
            }
        ),
        "WM_GETICON ICON_BIG returns stored icon 0xCAFE"
    );

    let get_small3 = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SEND_MESSAGE_W,
        [hwnd, WM_GETICON, ICON_SMALL, 0u32],
    );
    assert!(
        matches!(
            get_small3,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0xBEEF),
                ..
            }
        ),
        "WM_GETICON ICON_SMALL still returns 0xBEEF after ICON_BIG was set"
    );

    Ok(())
}

#[test]
fn coredll_raw_gwe_def_window_proc_enable_invalidates_window() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 1;

    let hwnd = kernel.create_window_ex_w_with_rect(
        thread_id,
        "TestClass",
        "Enable Test",
        None,
        0,
        WS_VISIBLE,
        0,
        Rect::from_origin_size(0, 0, 100, 100),
    );
    assert_ne!(hwnd, 0);

    // Drain the initial paint update.
    kernel.gwe.validate_window(hwnd);
    assert!(
        !kernel.gwe.window(hwnd).map_or(false, |w| w.update_pending),
        "No pending update after validate"
    );

    // DefWindowProcW(hwnd, WM_ENABLE, 1, 0) must invalidate the window.
    let result = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_DEF_WINDOW_PROC_W,
        [hwnd, WM_ENABLE, 1u32, 0u32],
    );
    assert!(
        matches!(
            result,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0),
                ..
            }
        ),
        "DefWindowProcW(WM_ENABLE) returns 0"
    );

    assert!(
        kernel.gwe.window(hwnd).map_or(false, |w| w.update_pending),
        "WM_ENABLE in DefWindowProcW must mark window as needing repaint"
    );

    Ok(())
}

#[test]
fn coredll_raw_translate_message_western_layout_ctrl_and_altgr() -> Result<()> {
    // Ctrl+letter on a Western layout must produce a WM_CHAR control code (not a layout character).
    // AltGr (Ctrl+Alt)+key must produce the AltGr character from the layout-specific table.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 55_u32;
    let msg_ptr = 0x3_0000_u32;
    memory.map_words(msg_ptr, 7);
    let hwnd = kernel.create_window_ex_w(thread_id, "CTRL_ALTGR_OWNER", "", None, 0, 0, 0);

    // Switch to French AZERTY (0x040C).
    kernel.gwe.activate_keyboard_layout(0x040C);

    // --- AZERTY Ctrl+Q: VK_Q maps to 'a' on AZERTY, but Ctrl must win → WM_CHAR(0x01=Ctrl+A). ---
    // Post Ctrl down so key state is set.
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYDOWN, VK_LCONTROL, 0);
    write_raw_message(&mut memory, msg_ptr, hwnd, WM_KEYDOWN, 0x51u32, 0)?; // VK_Q
    let r = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_TRANSLATE_MESSAGE,
        [msg_ptr],
    );
    assert!(
        matches!(
            r,
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ),
        "Ctrl+VK_Q on AZERTY must produce WM_CHAR (control code)"
    );
    let ctrl_msg = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("Ctrl+Q must post WM_CHAR(Ctrl+Q=0x11) not AZERTY layout char 'a'");
    // VK codes are layout-independent: VK_Q=0x51, so Ctrl+VK_Q → 0x51-0x40 = 0x11.
    assert_eq!(
        ctrl_msg.wparam, 0x11,
        "Ctrl+VK_Q on AZERTY should produce Ctrl+Q (0x11), not layout char 'a'"
    );
    // Release Ctrl.
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYUP, VK_LCONTROL, 0);

    // --- AZERTY AltGr+2: AltGr = Ctrl+Alt, must produce '~' (0x7e). ---
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYDOWN, VK_LCONTROL, 0);
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYDOWN, VK_MENU, 0);
    write_raw_message(&mut memory, msg_ptr, hwnd, WM_KEYDOWN, 0x32u32, 0)?; // VK_2
    let r2 = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_TRANSLATE_MESSAGE,
        [msg_ptr],
    );
    assert!(
        matches!(
            r2,
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ),
        "AltGr+2 on AZERTY must produce WM_CHAR"
    );
    let altgr_msg = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("AltGr+2 on AZERTY must post WM_CHAR('~')");
    assert_eq!(altgr_msg.wparam, 0x7e, "AltGr+2 on AZERTY → '~'");
    // Release AltGr.
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYUP, VK_MENU, 0);
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYUP, VK_LCONTROL, 0);

    // --- QWERTZ AltGr+Q → '@'. ---
    kernel.gwe.activate_keyboard_layout(0x0407);
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYDOWN, VK_LCONTROL, 0);
    kernel.post_message_w_for_thread(thread_id, hwnd, WM_KEYDOWN, VK_MENU, 0);
    write_raw_message(&mut memory, msg_ptr, hwnd, WM_KEYDOWN, 0x51u32, 0)?; // VK_Q
    let r3 = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_TRANSLATE_MESSAGE,
        [msg_ptr],
    );
    assert!(
        matches!(
            r3,
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        ),
        "AltGr+Q on QWERTZ must produce WM_CHAR"
    );
    let q_msg = kernel
        .gwe
        .peek_message_filtered(thread_id, Some(hwnd), WM_CHAR, WM_CHAR, PeekFlags::REMOVE)
        .expect("AltGr+Q on QWERTZ must post WM_CHAR('@')");
    assert_eq!(q_msg.wparam, 0x40, "AltGr+Q on QWERTZ → '@'");

    Ok(())
}

#[test]
fn coredll_raw_gwe_wm_parentnotify_on_create_and_destroy() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 1;

    // Write class name and title to guest memory.
    let class_ptr = 0x8000u32;
    let title_ptr = 0x8040u32;
    memory.write_wide_z(class_ptr, "TESTCHILD");
    memory.write_wide_z(title_ptr, "child");

    // Create parent via raw kernel call (no WM_PARENTNOTIFY for top-level).
    let parent = kernel.create_window_ex_w(thread_id, "PARENT", "parent", None, 0, 0, 0);
    assert_ne!(parent, 0);
    assert!(
        kernel.gwe.get_message(thread_id).is_none(),
        "No WM_PARENTNOTIFY for top-level window creation"
    );

    // Create child via coredll ORD_CREATE_WINDOW_EX_W → posts WM_PARENTNOTIFY(WM_CREATE).
    let child_id: u32 = 42;
    let child = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_WINDOW_EX_W,
        [
            0u32, class_ptr, title_ptr, WS_CHILD, 0, 0, 100, 80, parent, child_id, 0, 0,
        ],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(hwnd),
            ..
        } => hwnd,
        other => panic!("CreateWindowExW failed: {other:?}"),
    };
    assert_ne!(child, 0);

    let msg = kernel
        .gwe
        .get_message(thread_id)
        .expect("WM_PARENTNOTIFY(WM_CREATE) must be posted to parent");
    assert_eq!(msg.hwnd, parent, "WM_PARENTNOTIFY delivered to parent hwnd");
    assert_eq!(msg.msg, WM_PARENTNOTIFY);
    assert_eq!(
        msg.wparam & 0xffff,
        WM_CREATE,
        "Low word of wparam is WM_CREATE"
    );
    assert_eq!(
        msg.wparam >> 16,
        child_id,
        "High word of wparam is child control id"
    );
    assert_eq!(msg.lparam, child, "lparam is child hwnd");
    assert!(
        kernel.gwe.get_message(thread_id).is_none(),
        "No extra messages after create notify"
    );

    // Destroy child via coredll ORD_DESTROY_WINDOW → posts WM_PARENTNOTIFY(WM_DESTROY).
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_DESTROY_WINDOW,
            [child],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    let destroy_msg = kernel
        .gwe
        .get_message(thread_id)
        .expect("WM_PARENTNOTIFY(WM_DESTROY) must be posted to parent");
    assert_eq!(destroy_msg.hwnd, parent);
    assert_eq!(destroy_msg.msg, WM_PARENTNOTIFY);
    assert_eq!(
        destroy_msg.wparam & 0xffff,
        WM_DESTROY,
        "Low word of wparam is WM_DESTROY"
    );
    assert_eq!(
        destroy_msg.wparam >> 16,
        child_id,
        "High word of wparam is child control id"
    );
    assert_eq!(destroy_msg.lparam, child, "lparam is child hwnd");

    Ok(())
}

#[test]
fn coredll_raw_gwe_wm_parentnotify_suppressed_by_noparentnotify() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 1;

    let class_ptr = 0x8000u32;
    let title_ptr = 0x8040u32;
    memory.write_wide_z(class_ptr, "QUIETCHILD");
    memory.write_wide_z(title_ptr, "quiet");

    let parent = kernel.create_window_ex_w(thread_id, "PARENT", "parent", None, 0, 0, 0);
    assert_ne!(parent, 0);

    // Child created with WS_EX_NOPARENTNOTIFY must NOT post WM_PARENTNOTIFY.
    let child = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_WINDOW_EX_W,
        [
            WS_EX_NOPARENTNOTIFY,
            class_ptr,
            title_ptr,
            WS_CHILD,
            0,
            0,
            50,
            50,
            parent,
            7u32,
            0,
            0,
        ],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(hwnd),
            ..
        } => hwnd,
        other => panic!("CreateWindowExW failed: {other:?}"),
    };
    assert_ne!(child, 0);
    assert!(
        kernel.gwe.get_message(thread_id).is_none(),
        "WS_EX_NOPARENTNOTIFY must suppress WM_PARENTNOTIFY"
    );

    Ok(())
}

#[test]
fn coredll_raw_def_window_proc_cancelmode_releases_capture() -> Result<()> {
    // CE DefWindowProcW: WM_CANCELMODE should release mouse capture if the receiving
    // window currently holds it, posting WM_CAPTURECHANGED to itself.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 1;
    let msg_ptr = 0x9000u32;
    memory.map_words(msg_ptr, 7);

    let hwnd = kernel.create_window_ex_w(thread_id, "CAPTUREWIN", "", None, 0, 0, 0);
    assert_ne!(hwnd, 0);

    // Set capture on the window.
    let _ = kernel.set_capture(hwnd);
    assert_eq!(
        kernel.gwe.get_capture(),
        Some(hwnd),
        "capture should be set before WM_CANCELMODE"
    );

    // DefWindowProcW WM_CANCELMODE: capture window should release capture.
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_DEF_WINDOW_PROC_W,
        [hwnd, WM_CANCELMODE, 0u32, 0u32],
    );

    assert_eq!(
        kernel.gwe.get_capture(),
        None,
        "WM_CANCELMODE in DefWindowProcW must release capture"
    );

    // WM_CAPTURECHANGED must have been posted to the old capture window.
    let msg = kernel.gwe.peek_message_filtered(
        thread_id,
        Some(hwnd),
        WM_CAPTURECHANGED,
        WM_CAPTURECHANGED,
        PeekFlags::REMOVE,
    );
    assert!(
        msg.is_some(),
        "WM_CAPTURECHANGED must be posted after WM_CANCELMODE releases capture"
    );

    // WM_CANCELMODE on a non-capture window should be a no-op (no crash, no spurious release).
    let other = kernel.create_window_ex_w(thread_id, "OTHER", "", None, 0, 0, 0);
    let _ = kernel.set_capture(hwnd);
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_DEF_WINDOW_PROC_W,
        [other, WM_CANCELMODE, 0u32, 0u32],
    );
    assert_eq!(
        kernel.gwe.get_capture(),
        Some(hwnd),
        "WM_CANCELMODE on non-capture window must not release capture held by another window"
    );

    Ok(())
}

#[test]
fn coredll_raw_def_window_proc_help_forwards_to_parent() -> Result<()> {
    // CE DefWindowProcW: WM_HELP is forwarded to the parent window (like WM_CONTEXTMENU).
    // Both the forwarding call and the no-parent case must not crash.
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 2;
    let msg_ptr = 0x9200u32;
    memory.map_words(msg_ptr, 7);

    let parent = kernel.create_window_ex_w(thread_id, "HELPPARENT", "", None, 0, 0, 0);
    let child = kernel.create_window_ex_w(thread_id, "HELPCHILD", "", Some(parent), 0, 0, 0);

    // DefWindowProcW on child with WM_HELP must forward to parent without crashing.
    let result = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_DEF_WINDOW_PROC_W,
        [child, WM_HELP, 0u32, 0u32],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::U32(v),
            ..
        } => v,
        other => panic!("DefWindowProcW WM_HELP on child failed: {other:?}"),
    };
    assert_eq!(
        result, 0,
        "WM_HELP forwarded to parent with no WM_HELP handler returns 0"
    );
    assert!(
        kernel.gwe.is_window(parent),
        "parent must survive WM_HELP forwarding"
    );
    assert!(
        kernel.gwe.is_window(child),
        "child must survive WM_HELP forwarding"
    );

    // Top-level window with no parent: WM_HELP must not crash and returns 0.
    let result = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_DEF_WINDOW_PROC_W,
        [parent, WM_HELP, 0u32, 0u32],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::U32(v),
            ..
        } => v,
        other => panic!("DefWindowProcW WM_HELP on top-level failed: {other:?}"),
    };
    assert_eq!(
        result, 0,
        "WM_HELP on top-level window with no parent returns 0"
    );

    Ok(())
}

#[test]
fn coredll_raw_get_device_caps_returns_ce_display_capabilities() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 5;

    let hdc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DC,
        [0u32],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(h),
            ..
        } => h,
        other => panic!("GetDC failed: {other:?}"),
    };
    assert_ne!(hdc, 0);

    let caps: &[(u32, &str, u32)] = &[
        (0, "DRIVERVERSION", 0x0001_0000),
        (2, "TECHNOLOGY (DT_RASDISPLAY)", 1),
        (8, "HORZRES", 800),
        (10, "VERTRES", 480),
        (12, "BITSPIXEL", 16),
        (14, "PLANES", 1),
        (16, "NUMBRUSHES", u32::MAX),
        (18, "NUMPENS", u32::MAX),
        (20, "NUMMARKERS", u32::MAX),
        (22, "NUMFONTS", u32::MAX),
        (24, "NUMCOLORS", u32::MAX), // -1 cast: true-color/hi-color
        (36, "CLIPCAPS", 1),
        (40, "ASPECTX", 36),
        (42, "ASPECTY", 36),
        (44, "ASPECTXY", 51),
        (88, "LOGPIXELSX", 96),
        (90, "LOGPIXELSY", 96),
        (104, "SIZEPALETTE", 0),
        (106, "NUMRESERVED", 0),
        (108, "COLORRES", 16),
        (120, "SHADEBLENDCAPS", 0x0000_0017),
    ];
    for &(idx, name, expected) in caps {
        let got = match table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_DEVICE_CAPS,
            [hdc, idx],
        ) {
            CoredllDispatch::Returned {
                value: CoredllValue::U32(v),
                ..
            } => v,
            other => panic!("GetDeviceCaps({name}) failed: {other:?}"),
        };
        assert_eq!(got, expected, "GetDeviceCaps({name}) mismatch");
    }

    // Capability masks should be non-zero for a functional display.
    for &(idx, name) in &[
        (28u32, "CURVECAPS"),
        (30, "LINECAPS"),
        (32, "POLYGONALCAPS"),
        (34, "TEXTCAPS"),
        (38, "RASTERCAPS"),
    ] {
        let got = match table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_DEVICE_CAPS,
            [hdc, idx],
        ) {
            CoredllDispatch::Returned {
                value: CoredllValue::U32(v),
                ..
            } => v,
            other => panic!("GetDeviceCaps({name}) failed: {other:?}"),
        };
        assert_ne!(
            got, 0,
            "GetDeviceCaps({name}) should be non-zero for a CE display"
        );
    }

    // Unknown/unsupported index returns 0.
    let unknown = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DEVICE_CAPS,
        [hdc, 999u32],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::U32(v),
            ..
        } => v,
        other => panic!("GetDeviceCaps(999) failed: {other:?}"),
    };
    assert_eq!(unknown, 0, "unknown cap index returns 0");
    assert_eq!(kernel.threads.get_last_error(thread_id), 0);

    // CE assumes the primary display when passed a NULL HDC.
    let null_result = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DEVICE_CAPS,
        [0u32, 8u32],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::U32(v),
            ..
        } => v,
        other => panic!("GetDeviceCaps(null hdc) failed: {other:?}"),
    };
    assert_eq!(null_result, 800, "null HDC uses the primary display");
    assert_eq!(kernel.threads.get_last_error(thread_id), 0);

    let invalid_index = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_DEVICE_CAPS,
        [hdc, u32::MAX],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::U32(v),
            ..
        } => v,
        other => panic!("GetDeviceCaps(-1) failed: {other:?}"),
    };
    assert_eq!(invalid_index, 0);
    assert_eq!(
        kernel.threads.get_last_error(thread_id),
        ERROR_INVALID_PARAMETER
    );

    for bad_hdc in [0x1234_5678, 0x000b_5000] {
        let invalid_hdc = match table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_DEVICE_CAPS,
            [bad_hdc, 12],
        ) {
            CoredllDispatch::Returned {
                value: CoredllValue::U32(v),
                ..
            } => v,
            other => panic!("GetDeviceCaps(bad hdc) failed: {other:?}"),
        };
        assert_eq!(invalid_hdc, 0);
        assert_eq!(
            kernel.threads.get_last_error(thread_id),
            ERROR_INVALID_HANDLE
        );
    }

    Ok(())
}

#[test]
fn coredll_raw_adjust_window_rect_ex_expands_by_nonclient_area() -> Result<()> {
    // CE AdjustWindowRectEx expands a client rect to include the NC area.
    // WS_CAPTION = WS_BORDER|WS_DLGFRAME → 3px border + 24px caption at top.
    // WS_BORDER only → 1px border. WS_THICKFRAME → 3px border (same as WS_DLGFRAME).
    const WS_CAPTION: u32 = 0x00C0_0000;
    const WS_BORDER: u32 = 0x0080_0000;
    const WS_THICKFRAME: u32 = 0x0004_0000;
    const NO_MENU: u32 = 0;
    const HAS_MENU: u32 = 1;

    let config = RuntimeConfig::load_default()?;
    let table = CoredllExportTable::default();
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 3;
    let rect_ptr: u32 = 0x2000;
    memory.map_words(rect_ptr, 4);

    let dispatch_rect = |memory: &mut TestGuestMemory,
                         kernel: &mut CeKernel,
                         style: u32,
                         menu: u32,
                         l: i32,
                         t: i32,
                         r: i32,
                         b: i32| {
        memory.write_u32(rect_ptr, l as u32).unwrap();
        memory.write_u32(rect_ptr + 4, t as u32).unwrap();
        memory.write_u32(rect_ptr + 8, r as u32).unwrap();
        memory.write_u32(rect_ptr + 12, b as u32).unwrap();
        matches!(
            table.dispatch_raw_ordinal_with_memory(
                kernel,
                memory,
                thread_id,
                ORD_ADJUST_WINDOW_RECT_EX,
                [rect_ptr, style, menu, 0u32]
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::Bool(true),
                ..
            }
        )
    };

    // WS_CAPTION (WS_BORDER | WS_DLGFRAME): 3px border each side, 24px caption at top.
    // Input rect (10, 50, 210, 250) → left-=3, top-=3-24=27, right+=3, bottom+=3
    assert!(dispatch_rect(
        &mut memory,
        &mut kernel,
        WS_CAPTION,
        NO_MENU,
        10,
        50,
        210,
        250
    ));
    assert_eq!(
        memory.read_u32(rect_ptr)? as i32,
        10 - 3,
        "WS_CAPTION: left expands by 3"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 4)? as i32,
        50 - 3 - 24,
        "WS_CAPTION: top expands by 3+24"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 8)? as i32,
        210 + 3,
        "WS_CAPTION: right expands by 3"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 12)? as i32,
        250 + 3,
        "WS_CAPTION: bottom expands by 3"
    );

    // WS_BORDER only: 1px each side.
    assert!(dispatch_rect(
        &mut memory,
        &mut kernel,
        WS_BORDER,
        NO_MENU,
        10,
        50,
        210,
        250
    ));
    assert_eq!(
        memory.read_u32(rect_ptr)? as i32,
        10 - 1,
        "WS_BORDER: left expands by 1"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 4)? as i32,
        50 - 1,
        "WS_BORDER: top expands by 1"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 8)? as i32,
        210 + 1,
        "WS_BORDER: right expands by 1"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 12)? as i32,
        250 + 1,
        "WS_BORDER: bottom expands by 1"
    );

    // WS_THICKFRAME: 3px (SM_CXDLGFRAME) each side.
    assert!(dispatch_rect(
        &mut memory,
        &mut kernel,
        WS_THICKFRAME,
        NO_MENU,
        10,
        50,
        210,
        250
    ));
    assert_eq!(
        memory.read_u32(rect_ptr)? as i32,
        10 - 3,
        "WS_THICKFRAME: left expands by 3"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 4)? as i32,
        50 - 3,
        "WS_THICKFRAME: top expands by 3"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 8)? as i32,
        210 + 3,
        "WS_THICKFRAME: right expands by 3"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 12)? as i32,
        250 + 3,
        "WS_THICKFRAME: bottom expands by 3"
    );

    // No style (WS_POPUP/WS_CHILD): no NC area, rect unchanged.
    assert!(dispatch_rect(
        &mut memory,
        &mut kernel,
        0,
        NO_MENU,
        10,
        50,
        210,
        250
    ));
    assert_eq!(
        memory.read_u32(rect_ptr)? as i32,
        10,
        "no style: rect unchanged"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 4)? as i32,
        50,
        "no style: rect unchanged"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 8)? as i32,
        210,
        "no style: rect unchanged"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 12)? as i32,
        250,
        "no style: rect unchanged"
    );

    // WS_CAPTION with menu: top also subtracts SM_CYMENU (24).
    assert!(dispatch_rect(
        &mut memory,
        &mut kernel,
        WS_CAPTION,
        HAS_MENU,
        10,
        100,
        210,
        300
    ));
    assert_eq!(
        memory.read_u32(rect_ptr + 4)? as i32,
        100 - 3 - 24 - 24,
        "WS_CAPTION+menu: top -=3+24+24"
    );

    Ok(())
}

#[test]
fn coredll_raw_intersect_clip_rect_and_exclude_clip_rect_update_dc_clip() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 180_u32;
    let rect_ptr = 0x1_0000_u32;
    memory.map_words(rect_ptr, 4);

    let dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(h),
            ..
        } => h,
        _ => panic!("CREATE_COMPATIBLE_DC failed"),
    };
    assert_ne!(dc, 0);

    // IntersectClipRect with no prior clip: sets the clip region to the rect.
    // Returns SIMPLEREGION (2) for a non-empty single rect.
    let result = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_INTERSECT_CLIP_RECT,
        [dc, 10_u32, 20_u32, 100_u32, 80_u32],
    );
    assert!(
        matches!(
            result,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(2),
                ..
            }
        ),
        "IntersectClipRect must return SIMPLEREGION=2, got {result:?}"
    );

    // GetClipBox after IntersectClipRect: must return the intersected rect.
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_CLIP_BOX,
        [dc, rect_ptr],
    );
    assert_eq!(memory.read_u32(rect_ptr)? as i32, 10, "clip left");
    assert_eq!(memory.read_u32(rect_ptr + 4)? as i32, 20, "clip top");
    assert_eq!(memory.read_u32(rect_ptr + 8)? as i32, 100, "clip right");
    assert_eq!(memory.read_u32(rect_ptr + 12)? as i32, 80, "clip bottom");

    // Second IntersectClipRect narrows the existing clip.
    let result2 = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_INTERSECT_CLIP_RECT,
        [dc, 30_u32, 30_u32, 70_u32, 60_u32],
    );
    assert!(
        matches!(
            result2,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(2),
                ..
            }
        ),
        "second IntersectClipRect must return SIMPLEREGION=2, got {result2:?}"
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_CLIP_BOX,
        [dc, rect_ptr],
    );
    assert_eq!(memory.read_u32(rect_ptr)? as i32, 30, "narrowed clip left");
    assert_eq!(
        memory.read_u32(rect_ptr + 4)? as i32,
        30,
        "narrowed clip top"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 8)? as i32,
        70,
        "narrowed clip right"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 12)? as i32,
        60,
        "narrowed clip bottom"
    );

    // Clear clip via SelectClipRgn(dc, 0), then set a wide clip, then ExcludeClipRect.
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SELECT_CLIP_RGN,
        [dc, 0],
    );
    // Set clip to [0,0,200,100] via IntersectClipRect (no prior clip → new rect as clip).
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_INTERSECT_CLIP_RECT,
        [dc, 0_u32, 0_u32, 200_u32, 100_u32],
    );
    // ExcludeClipRect: removes [50,0,150,100] from [0,0,200,100] → two rects: [0,0,50,100] and [150,0,200,100].
    let ex_result = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_EXCLUDE_CLIP_RECT,
        [dc, 50_u32, 0_u32, 150_u32, 100_u32],
    );
    // Two rects remaining → COMPLEXREGION (3).
    assert!(
        matches!(
            ex_result,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(3),
                ..
            }
        ),
        "ExcludeClipRect leaving two rects must return COMPLEXREGION=3, got {ex_result:?}"
    );

    let implicit_dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC(implicit clip) did not return a handle: {other:?}"),
    };

    let oversize_result = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_INTERSECT_CLIP_RECT,
        [
            implicit_dc,
            (-10_i32) as u32,
            (-20_i32) as u32,
            820_u32,
            500_u32,
        ],
    );
    assert!(
        matches!(
            oversize_result,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(2),
                ..
            }
        ),
        "oversized IntersectClipRect must return SIMPLEREGION=2, got {oversize_result:?}"
    );
    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_GET_CLIP_BOX,
        [implicit_dc, rect_ptr],
    );
    assert_eq!(memory.read_u32(rect_ptr)? as i32, 0, "bounded clip left");
    assert_eq!(memory.read_u32(rect_ptr + 4)? as i32, 0, "bounded clip top");
    assert_eq!(
        memory.read_u32(rect_ptr + 8)? as i32,
        800,
        "bounded clip right"
    );
    assert_eq!(
        memory.read_u32(rect_ptr + 12)? as i32,
        480,
        "bounded clip bottom"
    );

    table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_SELECT_CLIP_RGN,
        [implicit_dc, 0],
    );
    let excluded = table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_EXCLUDE_CLIP_RECT,
        [implicit_dc, 100_u32, 100_u32, 200_u32, 200_u32],
    );
    assert!(
        matches!(
            excluded,
            CoredllDispatch::Returned {
                value: CoredllValue::U32(3),
                ..
            }
        ),
        "implicit ExcludeClipRect must return COMPLEXREGION=3, got {excluded:?}"
    );
    let out = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_RECT_RGN,
        [0, 0, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(region),
            ..
        } => region,
        other => panic!("CreateRectRgn(implicit out) did not return a region: {other:?}"),
    };
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_RGN,
            [implicit_dc, out],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(1),
            ..
        }
    ));
    assert_eq!(kernel.resources.region(out).unwrap().rects.len(), 4);

    Ok(())
}

#[test]
fn coredll_raw_clip_rect_entrypoints_validate_hdc_like_ce() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 182_u32;
    let rect_ptr = 0x1_0000_u32;
    memory.map_words(rect_ptr, 4);

    let dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC did not return a handle: {other:?}"),
    };

    for (ordinal, args) in [
        (
            ORD_INTERSECT_CLIP_RECT,
            [0xBAD0_0001, 10_u32, 10_u32, 50_u32, 50_u32],
        ),
        (
            ORD_EXCLUDE_CLIP_RECT,
            [0xBAD0_0002, 10_u32, 10_u32, 50_u32, 50_u32],
        ),
    ] {
        kernel.threads.set_last_error(thread_id, 0);
        assert!(matches!(
            table.dispatch_raw_ordinal_with_memory(
                &mut kernel,
                &mut memory,
                thread_id,
                ordinal,
                args,
            ),
            CoredllDispatch::Returned {
                value: CoredllValue::U32(0),
                ..
            }
        ));
        assert_eq!(
            kernel.threads.get_last_error(thread_id),
            ERROR_INVALID_HANDLE
        );
    }

    kernel.threads.set_last_error(thread_id, 0);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_BOX,
            [0xBAD0_0003, rect_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(0),
            ..
        }
    ));
    assert_eq!(
        kernel.threads.get_last_error(thread_id),
        ERROR_INVALID_HANDLE
    );

    kernel.threads.set_last_error(thread_id, 0);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_BOX,
            [dc, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(0),
            ..
        }
    ));
    assert_eq!(
        kernel.threads.get_last_error(thread_id),
        ERROR_INVALID_PARAMETER
    );

    kernel.threads.set_last_error(thread_id, 0xDEAD);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_BOX,
            [dc, rect_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(2),
            ..
        }
    ));
    assert_eq!(kernel.threads.get_last_error(thread_id), 0);

    Ok(())
}

#[test]
fn coredll_raw_select_clip_rgn_copies_region_lifetime_like_ce() -> Result<()> {
    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 181_u32;
    let rect_ptr = 0x1_0000_u32;
    memory.map_words(rect_ptr, 4);

    let dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC did not return a handle: {other:?}"),
    };
    let source = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_RECT_RGN,
        [10, 20, 50, 60],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateRectRgn(source) did not return a region: {other:?}"),
    };
    let out = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_RECT_RGN,
        [0, 0, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateRectRgn(out) did not return a region: {other:?}"),
    };

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_CLIP_RGN,
            [dc, source],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(2),
            ..
        }
    ));

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SET_RECT_RGN,
            [source, 100, 110, 120, 130],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_DELETE_OBJECT,
            [source],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_RGN,
            [dc, out],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(1),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_RGN_BOX,
            [out, rect_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(2),
            ..
        }
    ));
    assert_eq!(memory.read_u32(rect_ptr)? as i32, 10);
    assert_eq!(memory.read_u32(rect_ptr + 4)? as i32, 20);
    assert_eq!(memory.read_u32(rect_ptr + 8)? as i32, 50);
    assert_eq!(memory.read_u32(rect_ptr + 12)? as i32, 60);

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_CLIP_RGN,
            [dc, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(2),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_RGN,
            [dc, 0],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(0),
            ..
        }
    ));

    Ok(())
}

#[test]
fn coredll_raw_select_clip_rgn_copies_complex_region_lifetime_like_ce() -> Result<()> {
    const COMPLEXREGION: u32 = 3;
    const RGN_DIFF: u32 = 4;

    let table = CoredllExportTable::default();
    let config = RuntimeConfig::load_default()?;
    let mut kernel = CeKernel::boot(config);
    let mut memory = TestGuestMemory::default();
    let thread_id = 181_u32;
    let rect_ptr = 0x1_1000_u32;
    memory.map_words(rect_ptr, 4);

    let dc = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_COMPATIBLE_DC,
        [0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateCompatibleDC did not return a handle: {other:?}"),
    };
    let outer = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_RECT_RGN,
        [0, 0, 100, 100],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateRectRgn(outer) did not return a region: {other:?}"),
    };
    let inner = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_RECT_RGN,
        [25, 25, 75, 75],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateRectRgn(inner) did not return a region: {other:?}"),
    };
    let complex = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_RECT_RGN,
        [0, 0, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateRectRgn(complex) did not return a region: {other:?}"),
    };
    let out = match table.dispatch_raw_ordinal_with_memory(
        &mut kernel,
        &mut memory,
        thread_id,
        ORD_CREATE_RECT_RGN,
        [0, 0, 0, 0],
    ) {
        CoredllDispatch::Returned {
            value: CoredllValue::Handle(handle),
            ..
        } => handle,
        other => panic!("CreateRectRgn(out) did not return a region: {other:?}"),
    };

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_COMBINE_RGN,
            [complex, outer, inner, RGN_DIFF],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(COMPLEXREGION),
            ..
        }
    ));
    assert_eq!(kernel.resources.region(complex).unwrap().rects.len(), 4);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SELECT_CLIP_RGN,
            [dc, complex],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(COMPLEXREGION),
            ..
        }
    ));

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_SET_RECT_RGN,
            [complex, 1, 1, 2, 2],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_DELETE_OBJECT,
            [complex],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::Bool(true),
            ..
        }
    ));

    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_RGN,
            [dc, out],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(1),
            ..
        }
    ));
    let copied = kernel.resources.region(out).unwrap();
    assert_eq!(copied.rects.len(), 4);
    assert_eq!(copied.rect.left, 0);
    assert_eq!(copied.rect.top, 0);
    assert_eq!(copied.rect.right, 100);
    assert_eq!(copied.rect.bottom, 100);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_RGN_BOX,
            [out, rect_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(COMPLEXREGION),
            ..
        }
    ));
    assert_eq!(memory.read_u32(rect_ptr)? as i32, 0);
    assert_eq!(memory.read_u32(rect_ptr + 4)? as i32, 0);
    assert_eq!(memory.read_u32(rect_ptr + 8)? as i32, 100);
    assert_eq!(memory.read_u32(rect_ptr + 12)? as i32, 100);
    assert!(matches!(
        table.dispatch_raw_ordinal_with_memory(
            &mut kernel,
            &mut memory,
            thread_id,
            ORD_GET_CLIP_BOX,
            [dc, rect_ptr],
        ),
        CoredllDispatch::Returned {
            value: CoredllValue::U32(COMPLEXREGION),
            ..
        }
    ));
    assert_eq!(memory.read_u32(rect_ptr)? as i32, 0);
    assert_eq!(memory.read_u32(rect_ptr + 4)? as i32, 0);
    assert_eq!(memory.read_u32(rect_ptr + 8)? as i32, 100);
    assert_eq!(memory.read_u32(rect_ptr + 12)? as i32, 100);

    Ok(())
}
